SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpa_get_kep_return_piority_desc (as_keeping_item text , as_type_money text , as_coll text ) RETURNS varchar AS $body$
DECLARE

  ls_name varchar(200);
  ls_loantype sc_lon_m_rule.loan_type%type;
  ls_type varchar(100);

BEGIN

case left(as_keeping_item,2)
	when  'ML' then 
		if trim(both as_coll ) = 'CO' then
			ls_loantype		:= substr(as_keeping_item,3,2);
      begin
        select (loan_type) into STRICT ls_loantype
        from sc_lon_m_rule
        where priority_keep_coll = ls_loantype;	
      exception
      when too_many_rows then  return 'Error priority_keep_coll many rows is ' || ls_loantype;
      when no_data_found then ls_name	:= '<ไม่มีข้อมูล>';
      when others then CALL spa_dberror('FPA_GET_KEP_RETURN_PIORITY_DESC');
      end;
		else
			ls_loantype		:= substr(as_keeping_item,3,2);
		end if;
		begin
      select		loan_type_description 
      into STRICT			ls_name
      from			sc_lon_m_rule 
      where		  loan_type  = ls_loantype	;
    exception
    when no_data_found then ls_name	:= '<ไม่มีข้อมูล>';
    when others then CALL spa_dberror('FPA_GET_KEP_RETURN_PIORITY_DESC');
    end;

		ls_name		    := ls_loantype ||' '|| +ls_name;
 		ls_loantype		:= '';

	when 'MD' then
		ls_loantype		:= substr(as_keeping_item,3,2);
    begin
      select		deposit_name
      into STRICT			ls_name
      from			sc_dep_m_rule
      where		  deposit_type_code = ls_loantype;
    exception
    when no_data_found then ls_name	:= '<ไม่มีข้อมูล>';
    when others then CALL spa_dberror('FPA_GET_KEP_RETURN_PIORITY_DESC');
    end;

		ls_name		    := ls_loantype ||' '|| +ls_name;
		ls_loantype		:= '';

	else
		ls_name		:= '';
		select	keeping_type_name
		into STRICT		ls_name
		from		sc_kep_m_ucf_keeping_item_type
		where ( keeping_type_code = as_keeping_item );
		ls_name	:= trim(both ls_name);
    if coalesce(ls_name::text, '') = '' or len(ls_name) = 0 then
        ls_name := '<ไม่มีข้อมูล>';
    end if;

end case;

--ls_type= ' ' 
if  left(as_keeping_item,2) = 'ML' then
	case as_type_money
		when 'P' then
			ls_type		:= 'เงินต้น';
		when 'I' then
			ls_type		:= 'ดอกเบี้ย';
		when 'A' then
			ls_type		:= 'ดอกเบี้ยค้าง';
		when 'T' then
			ls_type		:= 'ดอกเบี้ยปัจจุบัน';
		else
			ls_type		:=  '<ไม่มีข้อมูล>';
	end case;
	ls_name	:= '('||  trim(both ls_type )||') ' ||trim(both ls_loantype ) || ' ' || trim(both ls_name );
else
	ls_name	:= trim(both ls_loantype ) || ' ' || trim(both ls_name );
end if;

if trim(both as_coll ) = 'CO' then
  ls_name := 'ฐานะผู้ค้ำฯ ' || ls_name;
end if;

return ls_name;


exception
when no_data_found then return null;
when others then CALL spa_dberror('FPA_GET_KEP_RETURN_PIORITY_DESC,'||as_keeping_item||'');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION fpa_get_kep_return_piority_desc (as_keeping_item text , as_type_money text , as_coll text ) FROM PUBLIC;

